WITH dependencies AS (/* Functions dependent on AWS extensions */ SELECT n.nspname AS schema_name, p.proname AS object_name, 'SOURCE_CODE' AS object_type, l.lanname AS object_language, ext.extname AS aws_extension_dependency FROM pg_proc AS p JOIN pg_namespace AS n ON (p.pronamespace = n.oid) JOIN pg_language AS l ON (p.prolang = l.oid) JOIN pg_depend AS d ON (p.oid = d.objid) JOIN pg_extension AS ext ON (d.refobjid = ext.oid) WHERE ext.extname IN ('aws_commons', 'aws_s3', 'aws_lambda') AND n.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) UNION ALL /* Tables, Views, or Indexes dependent on AWS extensions */ SELECT n.nspname AS schema_name, c.relname AS object_name, CASE c.relkind WHEN 'r' THEN 'TABLE' WHEN 'v' THEN 'VIEW' WHEN 'm' THEN 'MATERIALIZED_VIEW' WHEN 'i' THEN 'INDEX' ELSE 'OTHER_RELATION' END AS object_type, 'N/A' AS object_language, ext.extname AS aws_extension_dependency FROM pg_class AS c JOIN pg_namespace AS n ON (c.relnamespace = n.oid) JOIN pg_depend AS d ON (c.oid = d.objid) JOIN pg_extension AS ext ON (d.refobjid = ext.oid) WHERE ext.extname IN ('aws_commons', 'aws_s3', 'aws_lambda') AND n.nspname <> ALL(ARRAY['pg_catalog', 'information_schema'])) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, CHR(34) || schema_name || CHR(34) AS schema_name, CHR(34) || object_language || CHR(34) AS object_language, CHR(34) || object_type || CHR(34) AS object_type, CHR(34) || object_name || CHR(34) AS object_name, CHR(34) || aws_extension_dependency || CHR(34) AS aws_extension_dependency, COUNT(*) AS sct_function_reference_count FROM dependencies AS d GROUP BY 1, 2, 3, 4, 5, 6, 7, 8